17	template<typename Heap>
18	std::tuple<bool, bool, RTExploredNode> ConnectionRouter<Heap>::timing_driven_route_connection_from_route_tree(
19	    const RouteTreeNode& rt_root,
20	    RRNodeId sink_node,
21	    const t_conn_cost_params& cost_params,
22	    const t_bb& bounding_box,
23	    RouterStats& router_stats,
24	    const ConnectionParameters& conn_params) {
25	    router_stats_ = &router_stats;
26	    conn_params_ = &conn_params;
27	
28	    bool retry = timing_driven_route_connection_common_setup(rt_root, sink_node, cost_params, bounding_box);
29	
30	    if (!std::isinf(rr_node_route_inf_[sink_node].path_cost)) {
31	        // Only the `index`, `prev_edge`, and `rcv_path_backward_delay` fields of `out`
32	        // are used after this function returns.
33	        RTExploredNode out;
34	        out.index = sink_node;
35	        out.prev_edge = rr_node_route_inf_[sink_node].prev_edge;
36	        if (rcv_path_manager.is_enabled()) {
37	            out.rcv_path_backward_delay = rcv_path_data[sink_node]->backward_delay;
38	            rcv_path_manager.update_route_tree_set(rcv_path_data[sink_node]);
39	            rcv_path_manager.empty_heap();
40	        }
41	        heap_.empty_heap();
42	        return std::make_tuple(true, /*retry=*/false, out);
43	    } else {
44	        reset_path_costs();
45	        clear_modified_rr_node_info();
46	        heap_.empty_heap();
47	        rcv_path_manager.empty_heap();
48	        return std::make_tuple(false, retry, RTExploredNode());
49	    }
50	}
