52	template<typename Heap>
53	std::tuple<bool, bool, RTExploredNode> ConnectionRouter<Heap>::timing_driven_route_connection_from_route_tree_high_fanout(
54	    const RouteTreeNode& rt_root,
55	    RRNodeId sink_node,
56	    const t_conn_cost_params& cost_params,
57	    const t_bb& net_bounding_box,
58	    const SpatialRouteTreeLookup& spatial_rt_lookup,
59	    RouterStats& router_stats,
60	    const ConnectionParameters& conn_params) {
61	    router_stats_ = &router_stats;
62	    conn_params_ = &conn_params;
63	
64	    // re-explore route tree from root to add any new nodes (buildheap afterwards)
65	    // route tree needs to be repushed onto the heap since each node's cost is target specific
66	    t_bb high_fanout_bb = add_high_fanout_route_tree_to_heap(rt_root, sink_node, cost_params, spatial_rt_lookup, net_bounding_box);
67	    heap_.build_heap();
68	
69	    RRNodeId source_node = rt_root.inode;
70	
71	    if (heap_.is_empty_heap()) {
72	        VTR_LOG("No source in route tree: %s\n", describe_unrouteable_connection(source_node, sink_node, is_flat_).c_str());
73	        return std::make_tuple(false, false, RTExploredNode());
74	    }
75	
76	    VTR_LOGV_DEBUG(router_debug_, "  Routing to %d as high fanout net (BB: %d,%d,%d x %d,%d,%d)\n", sink_node,
77	                   high_fanout_bb.layer_min, high_fanout_bb.xmin, high_fanout_bb.ymin,
78	                   high_fanout_bb.layer_max, high_fanout_bb.xmax, high_fanout_bb.ymax);
79	
80	    bool retry_with_full_bb = false;
81	    timing_driven_route_connection_from_heap(sink_node, cost_params, high_fanout_bb);
82	
83	    if (std::isinf(rr_node_route_inf_[sink_node].path_cost)) {
84	        //Found no path, that may be due to an unlucky choice of existing route tree sub-set,
85	        //try again with the full route tree to be sure this is not an artifact of high-fanout routing
86	        VTR_LOGV(route_verbosity_ > 1, "No routing path found in high-fanout mode for net %zu connection (to sink_rr %d), retrying with full route tree\n", size_t(conn_params.net_id_), sink_node);
87	
88	        //Reset any previously recorded node costs so timing_driven_route_connection()
89	        //starts over from scratch.
90	        reset_path_costs();
91	        clear_modified_rr_node_info();
92	
93	        retry_with_full_bb = timing_driven_route_connection_common_setup(rt_root, sink_node, cost_params, net_bounding_box);
94	    }
95	
96	    if (std::isinf(rr_node_route_inf_[sink_node].path_cost)) {
97	        VTR_LOG("%s\n", describe_unrouteable_connection(source_node, sink_node, is_flat_).c_str());
98	
99	        heap_.empty_heap();
100	        rcv_path_manager.empty_heap();
101	        return std::make_tuple(false, retry_with_full_bb, RTExploredNode());
102	    }
103	
104	    RTExploredNode out;
105	    out.index = sink_node;
106	    out.prev_edge = rr_node_route_inf_[sink_node].prev_edge;
107	    if (rcv_path_manager.is_enabled()) {
108	        out.rcv_path_backward_delay = rcv_path_data[sink_node]->backward_delay;
109	        rcv_path_manager.update_route_tree_set(rcv_path_data[sink_node]);
110	        rcv_path_manager.empty_heap();
111	    }
112	    heap_.empty_heap();
113	
114	    return std::make_tuple(true, retry_with_full_bb, out);
115	}
