117	template<typename Heap>
118	bool ConnectionRouter<Heap>::timing_driven_route_connection_common_setup(
119	    const RouteTreeNode& rt_root,
120	    RRNodeId sink_node,
121	    const t_conn_cost_params& cost_params,
122	    const t_bb& bounding_box) {
123	    //Re-add route nodes from the existing route tree to the heap.
124	    //They need to be repushed onto the heap since each node's cost is target specific.
125	
126	    add_route_tree_to_heap(rt_root, sink_node, cost_params, bounding_box);
127	    heap_.build_heap(); // via sifting down everything
128	
129	    RRNodeId source_node = rt_root.inode;
130	
131	    if (heap_.is_empty_heap()) {
132	        VTR_LOG("No source in route tree: %s\n", describe_unrouteable_connection(source_node, sink_node, is_flat_).c_str());
133	        return false;
134	    }
135	
136	    VTR_LOGV_DEBUG(router_debug_, "  Routing to %d as normal net (BB: %d,%d,%d x %d,%d,%d)\n", sink_node,
137	                   bounding_box.layer_min, bounding_box.xmin, bounding_box.ymin,
138	                   bounding_box.layer_max, bounding_box.xmax, bounding_box.ymax);
139	
140	    timing_driven_route_connection_from_heap(sink_node, cost_params, bounding_box);
141	
142	    if (std::isinf(rr_node_route_inf_[sink_node].path_cost)) {
143	        // No path found within the current bounding box.
144	        //
145	        // If the bounding box is already max size, just fail
146	        if (bounding_box.xmin == 0
147	            && bounding_box.ymin == 0
148	            && bounding_box.xmax == (int)(grid_.width() - 1)
149	            && bounding_box.ymax == (int)(grid_.height() - 1)
150	            && bounding_box.layer_min == 0
151	            && bounding_box.layer_max == (int)(grid_.get_num_layers() - 1)) {
152	            VTR_LOG("%s\n", describe_unrouteable_connection(source_node, sink_node, is_flat_).c_str());
153	            return false;
154	        }
155	
156	        // Otherwise, leave unrouted and bubble up a signal to retry this net with a full-device bounding box
157	        VTR_LOGV(route_verbosity_ > 1, "No routing path for connection to sink_rr %d, leaving unrouted to retry later\n", sink_node);
158	        return true;
159	    }
160	
161	    return false;
162	}
