164	template<typename Heap>
165	void ConnectionRouter<Heap>::timing_driven_route_connection_from_heap(RRNodeId sink_node,
166	                                                                      const t_conn_cost_params& cost_params,
167	                                                                      const t_bb& bounding_box) {
168	    VTR_ASSERT_SAFE(heap_.is_valid());
169	
170	    if (heap_.is_empty_heap()) { //No source
171	        VTR_LOGV_DEBUG(router_debug_, "  Initial heap empty (no source)\n");
172	    }
173	
174	    // Get bounding box for sink node used in timing_driven_expand_neighbour
175	    VTR_ASSERT_SAFE(sink_node != RRNodeId::INVALID());
176	
177	    t_bb target_bb;
178	    if (rr_graph_->node_type(sink_node) == e_rr_type::SINK) { // We need to get a bounding box for the sink's entire tile
179	        vtr::Rect<int> tile_bb = grid_.get_tile_bb({rr_graph_->node_xlow(sink_node),
180	                                                    rr_graph_->node_ylow(sink_node),
181	                                                    rr_graph_->node_layer_low(sink_node)});
182	
183	        target_bb.xmin = tile_bb.xmin();
184	        target_bb.ymin = tile_bb.ymin();
185	        target_bb.xmax = tile_bb.xmax();
186	        target_bb.ymax = tile_bb.ymax();
187	    } else {
188	        target_bb.xmin = rr_graph_->node_xlow(sink_node);
189	        target_bb.ymin = rr_graph_->node_ylow(sink_node);
190	        target_bb.xmax = rr_graph_->node_xhigh(sink_node);
191	        target_bb.ymax = rr_graph_->node_yhigh(sink_node);
192	    }
193	
194	    target_bb.layer_min = rr_graph_->node_layer_low(RRNodeId(sink_node));
195	    target_bb.layer_max = rr_graph_->node_layer_high(RRNodeId(sink_node));
196	
197	    // Start measuring path search time
198	    std::chrono::steady_clock::time_point begin_time = std::chrono::steady_clock::now();
199	
200	    timing_driven_find_single_shortest_path_from_heap(sink_node, cost_params, bounding_box, target_bb);
201	
202	    // Stop measuring path search time
203	    std::chrono::steady_clock::time_point end_time = std::chrono::steady_clock::now();
204	    path_search_cumulative_time += std::chrono::duration_cast<std::chrono::microseconds>(end_time - begin_time);
205	}
