226	template<typename Heap>
227	float ConnectionRouter<Heap>::compute_node_cost_using_rcv(const t_conn_cost_params cost_params,
228	                                                          RRNodeId to_node,
229	                                                          RRNodeId target_node,
230	                                                          float backwards_delay,
231	                                                          float backwards_cong,
232	                                                          float R_upstream) {
233	    const t_conn_delay_budget* delay_budget = cost_params.delay_budget;
234	    // TODO: This function is not tested for is_flat == true
235	    VTR_ASSERT(is_flat_ != true);
236	    const auto [expected_delay, expected_cong] = router_lookahead_.get_expected_delay_and_cong(to_node, target_node, cost_params, R_upstream);
237	
238	    float expected_total_cong = expected_cong + backwards_cong;
239	    float expected_total_delay = expected_delay + backwards_delay;
240	
241	    //If budgets specified calculate cost as described by RCV paper:
242	    //    R. Fung, V. Betz and W. Chow, "Slack Allocation and Routing to Improve FPGA Timing While
243	    //     Repairing Short-Path Violations," in IEEE Transactions on Computer-Aided Design of
244	    //     Integrated Circuits and Systems, vol. 27, no. 4, pp. 686-697, April 2008.
245	
246	    // Normalization constant defined in RCV paper cited above
247	    constexpr float NORMALIZATION_CONSTANT = 100e-12;
248	
249	    float expected_total_delay_cost = expected_total_delay;
250	    expected_total_delay_cost += (delay_budget->short_path_criticality + cost_params.criticality) * std::max(0.f, delay_budget->target_delay - expected_total_delay);
251	    // expected_total_delay_cost += std::pow(std::max(0.f, expected_total_delay - delay_budget->max_delay), 2) / NORMALIZATION_CONSTANT;
252	    expected_total_delay_cost += std::pow(std::max(0.f, delay_budget->min_delay - expected_total_delay), 2) / NORMALIZATION_CONSTANT;
253	    float expected_total_cong_cost = expected_total_cong;
254	
255	    float total_cost = expected_total_delay_cost + expected_total_cong_cost;
256	
257	    return total_cost;
258	}
