260	template<typename Heap>
261	void ConnectionRouter<Heap>::evaluate_timing_driven_node_costs(RTExploredNode* to,
262	                                                               const t_conn_cost_params& cost_params,
263	                                                               RRNodeId from_node,
264	                                                               RRNodeId target_node) {
265	    /* new_costs.backward_cost: is the "known" part of the cost to this node -- the
266	     * congestion cost of all the routing resources back to the existing route
267	     * plus the known delay of the total path back to the source.
268	     *
269	     * new_costs.total_cost: is this "known" backward cost + an expected cost to get to the target.
270	     *
271	     * new_costs.R_upstream: is the upstream resistance at the end of this node
272	     */
273	
274	    //Info for the switch connecting from_node to_node (i.e., to->index)
275	    int iswitch = rr_nodes_.edge_switch(to->prev_edge);
276	    bool switch_buffered = rr_switch_inf_[iswitch].buffered();
277	    bool reached_configurably = rr_switch_inf_[iswitch].configurable();
278	    float switch_R = rr_switch_inf_[iswitch].R;
279	    float switch_Cinternal = rr_switch_inf_[iswitch].Cinternal;
280	
281	    //To node info
282	    auto rc_index = rr_graph_->node_rc_index(to->index);
283	    float node_R = rr_rc_data_[rc_index].R;
284	
285	    //From node info
286	    float from_node_R = rr_rc_data_[rr_graph_->node_rc_index(from_node)].R;
287	
288	    //Update R_upstream
289	    if (switch_buffered) {
290	        to->R_upstream = 0.; //No upstream resistance
291	    } else {
292	        //R_Upstream already initialized
293	    }
294	
295	    to->R_upstream += switch_R; //Switch resistance
296	    to->R_upstream += node_R;   //Node resistance
297	
298	    //Calculate delay
299	    float Tdel = get_rr_node_delay_cost(to->index, to->prev_edge);
300	
301	    //Depending on the switch used, the Tdel of the upstream node (from_node) may change due to
302	    //increased loading from the switch's internal capacitance.
303	    //
304	    //Even though this delay physically affects from_node, we make the adjustment (now) on the to_node,
305	    //since only once we've reached to to_node do we know the connection used (and the switch enabled).
306	    //
307	    //To adjust for the time delay, we compute the product of the Rdel associated with from_node and
308	    //the internal capacitance of the switch.
309	    //
310	    //First, we will calculate Rdel_adjust (just like in the computation for Rdel, we consider only
311	    //half of from_node's resistance).
312	    float Rdel_adjust = to->R_upstream - 0.5 * from_node_R;
313	
314	    //Second, we adjust the Tdel to account for the delay caused by the internal capacitance.
315	    Tdel += Rdel_adjust * switch_Cinternal;
316	
317	    float cong_cost = 0.;
318	    if (reached_configurably) {
319	        cong_cost = get_rr_cong_cost(to->index, cost_params.pres_fac);
320	    } else {
321	        //Reached by a non-configurable edge.
322	        //Therefore the from_node and to_node are part of the same non-configurable node set.
323	#ifdef VTR_ASSERT_SAFE_ENABLED
324	        VTR_ASSERT_SAFE_MSG(same_non_config_node_set(from_node, to->index),
325	                            "Non-configurably connected edges should be part of the same node set");
326	#endif
327	
328	        //The congestion cost of all nodes in the set has already been accounted for (when
329	        //the current path first expanded a node in the set). Therefore do *not* re-add the congestion
330	        //cost.
331	        cong_cost = 0.;
332	    }
333	    if (conn_params_->router_opt_choke_points_ && is_flat_ && rr_graph_->node_type(to->index) == e_rr_type::IPIN) {
334	        auto find_res = conn_params_->connection_choking_spots_.find(to->index);
335	        if (find_res != conn_params_->connection_choking_spots_.end()) {
336	            cong_cost = cong_cost / pow(2, (float)find_res->second);
337	        }
338	    }
339	
340	    //Update the backward cost (upstream already included)
341	    to->backward_path_cost += (1. - cost_params.criticality) * cong_cost; //Congestion cost
342	    to->backward_path_cost += cost_params.criticality * Tdel;             //Delay cost
343	
344	    if (cost_params.bend_cost != 0.) {
345	        e_rr_type from_type = rr_graph_->node_type(from_node);
346	        e_rr_type to_type = rr_graph_->node_type(to->index);
347	        if ((from_type == e_rr_type::CHANX && to_type == e_rr_type::CHANY) || (from_type == e_rr_type::CHANY && to_type == e_rr_type::CHANX)) {
348	            to->backward_path_cost += cost_params.bend_cost; //Bend cost
349	        }
350	    }
351	
352	    float total_cost = 0.;
353	
354	    if (rcv_path_manager.is_enabled() && to->path_data != nullptr) {
355	        to->path_data->backward_delay += cost_params.criticality * Tdel;
356	        to->path_data->backward_cong += (1. - cost_params.criticality) * get_rr_cong_cost(to->index, cost_params.pres_fac);
357	
358	        total_cost = compute_node_cost_using_rcv(cost_params, to->index, target_node, to->path_data->backward_delay, to->path_data->backward_cong, to->R_upstream);
359	    } else {
360	        const auto& device_ctx = g_vpr_ctx.device();
361	        //Update total cost
362	        float expected_cost = router_lookahead_.get_expected_cost(to->index, target_node, cost_params, to->R_upstream);
363	        VTR_LOGV_DEBUG(router_debug_ && !std::isfinite(expected_cost),
364	                       "        Lookahead from %s (%s) to %s (%s) is non-finite, expected_cost = %f, to->R_upstream = %f\n",
365	                       rr_node_arch_name(to->index, is_flat_).c_str(),
366	                       describe_rr_node(device_ctx.rr_graph, device_ctx.grid, device_ctx.rr_indexed_data, to->index, is_flat_).c_str(),
367	                       rr_node_arch_name(target_node, is_flat_).c_str(),
368	                       describe_rr_node(device_ctx.rr_graph, device_ctx.grid, device_ctx.rr_indexed_data, target_node, is_flat_).c_str(),
369	                       expected_cost, to->R_upstream);
370	        total_cost += to->backward_path_cost + cost_params.astar_fac * std::max(0.f, expected_cost - cost_params.astar_offset);
371	    }
372	    to->total_cost = total_cost;
373	}
374	
375	template<typename Heap>
376	void ConnectionRouter<Heap>::add_route_tree_to_heap(
377	    const RouteTreeNode& rt_node,
378	    RRNodeId target_node,
379	    const t_conn_cost_params& cost_params,
380	    const t_bb& net_bb) {
381	    /* Puts the entire partial routing below and including rt_node onto the heap *
382	     * (except for those parts marked as not to be expanded) by calling itself   *
383	     * recursively.                                                              */
384	
385	    /* Pre-order depth-first traversal */
386	    // IPINs and SINKS are not re_expanded
387	    if (rt_node.re_expand) {
388	        add_route_tree_node_to_heap(rt_node, target_node, cost_params, net_bb);
389	    }
390	
391	    for (const RouteTreeNode& child_node : rt_node.child_nodes()) {
392	        if (is_flat_) {
393	            if (relevant_node_to_target(rr_graph_, child_node.inode, target_node)) {
394	                add_route_tree_to_heap(child_node, target_node, cost_params, net_bb);
395	            }
396	        } else {
397	            add_route_tree_to_heap(child_node, target_node, cost_params, net_bb);
398	        }
399	    }
400	}
