402	/* Expand bb by inode's extents and clip against net_bb */
403	inline void expand_highfanout_bounding_box(t_bb& bb, const t_bb& net_bb, RRNodeId inode, const RRGraphView* rr_graph) {
404	    bb.xmin = std::max<int>(net_bb.xmin, std::min<int>(bb.xmin, rr_graph->node_xlow(inode)));
405	    bb.ymin = std::max<int>(net_bb.ymin, std::min<int>(bb.ymin, rr_graph->node_ylow(inode)));
406	    bb.xmax = std::min<int>(net_bb.xmax, std::max<int>(bb.xmax, rr_graph->node_xhigh(inode)));
407	    bb.ymax = std::min<int>(net_bb.ymax, std::max<int>(bb.ymax, rr_graph->node_yhigh(inode)));
408	    bb.layer_min = std::min<int>(bb.layer_min, rr_graph->node_layer_low(inode));
409	    bb.layer_max = std::max<int>(bb.layer_max, rr_graph->node_layer_high(inode));
410	}
411	
412	/* Expand bb by HIGH_FANOUT_BB_FAC and clip against net_bb */
413	inline void adjust_highfanout_bounding_box(t_bb& bb, const t_bb& net_bb) {
414	    constexpr int HIGH_FANOUT_BB_FAC = 3;
415	
416	    bb.xmin = std::max<int>(net_bb.xmin, bb.xmin - HIGH_FANOUT_BB_FAC);
417	    bb.ymin = std::max<int>(net_bb.ymin, bb.ymin - HIGH_FANOUT_BB_FAC);
418	    bb.xmax = std::min<int>(net_bb.xmax, bb.xmax + HIGH_FANOUT_BB_FAC);
419	    bb.ymax = std::min<int>(net_bb.ymax, bb.ymax + HIGH_FANOUT_BB_FAC);
420	    bb.layer_min = std::min<int>(net_bb.layer_min, bb.layer_min);
421	    bb.layer_max = std::max<int>(net_bb.layer_max, bb.layer_max);
422	}
423	
424	template<typename Heap>
425	t_bb ConnectionRouter<Heap>::add_high_fanout_route_tree_to_heap(
426	    const RouteTreeNode& rt_root,
427	    RRNodeId target_node,
428	    const t_conn_cost_params& cost_params,
429	    const SpatialRouteTreeLookup& spatial_rt_lookup,
430	    const t_bb& net_bounding_box) {
431	    //For high fanout nets we only add those route tree nodes which are spatially close
432	    //to the sink.
433	    //
434	    //Based on:
435	    //  J. Swartz, V. Betz, J. Rose, "A Fast Routability-Driven Router for FPGAs", FPGA, 1998
436	    //
437	    //We rely on a grid-based spatial look-up which is maintained for high fanout nets by
438	    //update_route_tree(), which allows us to add spatially close route tree nodes without traversing
439	    //the entire route tree (which is likely large for a high fanout net).
440	
441	    //Determine which bin the target node is located in
442	
443	    int target_bin_x = grid_to_bin_x(rr_graph_->node_xlow(target_node), spatial_rt_lookup);
444	    int target_bin_y = grid_to_bin_y(rr_graph_->node_ylow(target_node), spatial_rt_lookup);
445	
446	    short target_layer = rr_graph_->node_layer_low(target_node);
447	
448	    int chan_nodes_added = 0;
449	
450	    t_bb highfanout_bb;
451	    highfanout_bb.xmin = rr_graph_->node_xlow(target_node);
452	    highfanout_bb.xmax = rr_graph_->node_xhigh(target_node);
453	    highfanout_bb.ymin = rr_graph_->node_ylow(target_node);
454	    highfanout_bb.ymax = rr_graph_->node_yhigh(target_node);
455	    highfanout_bb.layer_min = rr_graph_->node_layer_low(target_node);
456	    highfanout_bb.layer_max = rr_graph_->node_layer_high(target_node);
457	
458	    //Add existing routing starting from the target bin.
459	    //If the target's bin has insufficient existing routing add from the surrounding bins
460	    constexpr int SINGLE_BIN_MIN_NODES = 2;
461	    bool done = false;
462	    bool found_node_on_same_layer = false;
463	    for (int dx : {0, -1, +1}) {
464	        size_t bin_x = target_bin_x + dx;
465	
466	        if (bin_x > spatial_rt_lookup.dim_size(0) - 1) continue; //Out of range
467	
468	        for (int dy : {0, -1, +1}) {
469	            size_t bin_y = target_bin_y + dy;
470	
471	            if (bin_y > spatial_rt_lookup.dim_size(1) - 1) continue; //Out of range
472	
473	            for (const RouteTreeNode& rt_node : spatial_rt_lookup[bin_x][bin_y]) {
474	                if (!rt_node.re_expand) // Some nodes (like IPINs) shouldn't be re-expanded
475	                    continue;
476	                RRNodeId rr_node_to_add = rt_node.inode;
477	
478	                /* Flat router: don't go into clusters other than the target one */
479	                if (is_flat_) {
480	                    if (!relevant_node_to_target(rr_graph_, rr_node_to_add, target_node))
481	                        continue;
482	                }
483	
484	                /* In case of the parallel router, we may be dealing with a virtual net
485	                 * so prune the nodes from the HF lookup against the bounding box just in case */
486	                if (!inside_bb(rr_node_to_add, net_bounding_box))
487	                    continue;
488	
489	                auto rt_node_layer_num = rr_graph_->node_layer_low(rr_node_to_add);
490	                if (rt_node_layer_num == target_layer)
491	                    found_node_on_same_layer = true;
492	
493	                // Put the node onto the heap
494	                add_route_tree_node_to_heap(rt_node, target_node, cost_params, net_bounding_box);
495	
496	                // Expand HF BB to include the node (clip by original BB)
497	                expand_highfanout_bounding_box(highfanout_bb, net_bounding_box, rr_node_to_add, rr_graph_);
498	
499	                if (rr_graph_->node_type(rr_node_to_add) == e_rr_type::CHANY || rr_graph_->node_type(rr_node_to_add) == e_rr_type::CHANX) {
500	                    chan_nodes_added++;
501	                }
502	            }
503	
504	            if (dx == 0 && dy == 0 && chan_nodes_added > SINGLE_BIN_MIN_NODES && found_node_on_same_layer) {
505	                //Target bin contained at least minimum amount of routing
506	                //
507	                //We require at least SINGLE_BIN_MIN_NODES to be added.
508	                //This helps ensure we don't end up with, for example, a single
509	                //routing wire running in the wrong direction which may not be
510	                //able to reach the target within the bounding box.
511	                done = true;
512	                break;
513	            }
514	        }
515	        if (done) break;
516	    }
517	    /* If we didn't find enough nodes to branch off near the target
518	     * or they are on the wrong grid layer, just add the full route tree */
519	    if (chan_nodes_added <= SINGLE_BIN_MIN_NODES || !found_node_on_same_layer) {
520	        add_route_tree_to_heap(rt_root, target_node, cost_params, net_bounding_box);
521	        return net_bounding_box;
522	    } else {
523	        //We found nearby routing, replace original bounding box to be localized around that routing
524	        adjust_highfanout_bounding_box(highfanout_bb, net_bounding_box);
525	        return highfanout_bb;
526	    }
527	}
528	
529	/** Used for the flat router. The node isn't relevant to the target if
530	 * it is an intra-block node outside of our target block */
531	inline bool relevant_node_to_target(const RRGraphView* rr_graph,
532	                                    RRNodeId node_to_add,
533	                                    RRNodeId target_node) {
534	    VTR_ASSERT_SAFE(rr_graph->node_type(target_node) == e_rr_type::SINK);
535	    auto node_to_add_type = rr_graph->node_type(node_to_add);
536	    return node_to_add_type != e_rr_type::IPIN || node_in_same_physical_tile(node_to_add, target_node);
537	}
