7	/** Used to update router statistics for serial connection router */
8	inline void update_serial_router_stats(RouterStats* router_stats,
9	                                       bool is_push,
10	                                       RRNodeId rr_node_id,
11	                                       const RRGraphView* rr_graph);
12	
13	template<typename Heap>
14	void SerialConnectionRouter<Heap>::timing_driven_find_single_shortest_path_from_heap(RRNodeId sink_node,
15	                                                                                     const t_conn_cost_params& cost_params,
16	                                                                                     const t_bb& bounding_box,
17	                                                                                     const t_bb& target_bb) {
18	    const auto& device_ctx = g_vpr_ctx.device();
19	    auto& route_ctx = g_vpr_ctx.mutable_routing();
20	
21	    HeapNode cheapest;
22	    while (this->heap_.try_pop(cheapest)) {
23	        // Pop a new inode with the cheapest total cost in current route tree to be expanded on
24	        const auto& [new_total_cost, inode] = cheapest;
25	        update_serial_router_stats(this->router_stats_,
26	                                   /*is_push=*/false,
27	                                   inode,
28	                                   this->rr_graph_);
29	
30	        VTR_LOGV_DEBUG(this->router_debug_, "  Popping node %d (cost: %g)\n",
31	                       inode, new_total_cost);
32	
33	        // Have we found the target?
34	        if (inode == sink_node) {
35	            // If we're running RCV, the path will be stored in the path_data->path_rr vector
36	            // This is then placed into the traceback so that the correct path is returned
37	            // TODO: This can be eliminated by modifying the actual traceback function in route_timing
38	            if (this->rcv_path_manager.is_enabled()) {
39	                this->rcv_path_manager.insert_backwards_path_into_traceback(this->rcv_path_data[inode],
40	                                                                            this->rr_node_route_inf_[inode].path_cost,
41	                                                                            this->rr_node_route_inf_[inode].backward_path_cost,
42	                                                                            route_ctx);
43	            }
44	            VTR_LOGV_DEBUG(this->router_debug_, "  Found target %8d (%s)\n", inode, describe_rr_node(device_ctx.rr_graph, device_ctx.grid, device_ctx.rr_indexed_data, inode, this->is_flat_).c_str());
45	            break;
46	        }
47	
48	        // If not, keep searching
49	        timing_driven_expand_cheapest(inode,
50	                                      new_total_cost,
51	                                      sink_node,
52	                                      cost_params,
53	                                      bounding_box,
54	                                      target_bb);
55	    }
56	}
57	
58	template<typename Heap>
59	vtr::vector<RRNodeId, RTExploredNode> SerialConnectionRouter<Heap>::timing_driven_find_all_shortest_paths_from_route_tree(
60	    const RouteTreeNode& rt_root,
61	    const t_conn_cost_params& cost_params,
62	    const t_bb& bounding_box,
63	    RouterStats& router_stats,
64	    const ConnectionParameters& conn_params) {
65	    this->router_stats_ = &router_stats;
66	    this->conn_params_ = &conn_params;
67	
68	    // Add the route tree to the heap with no specific target node
69	    RRNodeId target_node = RRNodeId::INVALID();
70	    this->add_route_tree_to_heap(rt_root, target_node, cost_params, bounding_box);
71	    this->heap_.build_heap(); // via sifting down everything
72	
73	    auto res = timing_driven_find_all_shortest_paths_from_heap(cost_params, bounding_box);
74	    this->heap_.empty_heap();
75	
76	    return res;
77	}
78	
79	template<typename Heap>
80	vtr::vector<RRNodeId, RTExploredNode> SerialConnectionRouter<Heap>::timing_driven_find_all_shortest_paths_from_heap(
81	    const t_conn_cost_params& cost_params,
82	    const t_bb& bounding_box) {
83	    // Since there is no single *target* node this uses Dijkstra's algorithm
84	    // with a modified exit condition (runs until heap is empty).
85	
86	    vtr::vector<RRNodeId, RTExploredNode> cheapest_paths(this->rr_nodes_.size());
87	
88	    VTR_ASSERT_SAFE(this->heap_.is_valid());
89	
90	    if (this->heap_.is_empty_heap()) { // No source
91	        VTR_LOGV_DEBUG(this->router_debug_, "  Initial heap empty (no source)\n");
92	    }
93	
94	    // Start measuring path search time
95	    std::chrono::steady_clock::time_point begin_time = std::chrono::steady_clock::now();
96	
97	    HeapNode cheapest;
98	    while (this->heap_.try_pop(cheapest)) {
99	        // Pop a new inode with the cheapest total cost in current route tree to be expanded on
100	        const auto& [new_total_cost, inode] = cheapest;
101	        update_serial_router_stats(this->router_stats_,
102	                                   /*is_push=*/false,
103	                                   inode,
104	                                   this->rr_graph_);
105	
106	        VTR_LOGV_DEBUG(this->router_debug_, "  Popping node %d (cost: %g)\n",
107	                       inode, new_total_cost);
108	
109	        // Since we want to find shortest paths to all nodes in the graph
110	        // we do not specify a target node.
111	        //
112	        // By setting the target_node to INVALID in combination with the NoOp router
113	        // lookahead we can reuse the node exploration code from the regular router
114	        RRNodeId target_node = RRNodeId::INVALID();
115	
116	        timing_driven_expand_cheapest(inode,
117	                                      new_total_cost,
118	                                      target_node,
119	                                      cost_params,
120	                                      bounding_box,
121	                                      t_bb());
122	
123	        if (cheapest_paths[inode].index == RRNodeId::INVALID() || cheapest_paths[inode].total_cost >= new_total_cost) {
124	            VTR_LOGV_DEBUG(this->router_debug_, "  Better cost to node %d: %g (was %g)\n", inode, new_total_cost, cheapest_paths[inode].total_cost);
125	            // Only the `index` and `prev_edge` fields of `cheapest_paths[inode]` are used after this function returns
126	            cheapest_paths[inode].index = inode;
127	            cheapest_paths[inode].prev_edge = this->rr_node_route_inf_[inode].prev_edge;
128	        } else {
129	            VTR_LOGV_DEBUG(this->router_debug_, "  Worse cost to node %d: %g (better %g)\n", inode, new_total_cost, cheapest_paths[inode].total_cost);
130	        }
131	    }
132	
133	    // Stop measuring path search time
134	    std::chrono::steady_clock::time_point end_time = std::chrono::steady_clock::now();
135	    this->path_search_cumulative_time += std::chrono::duration_cast<std::chrono::microseconds>(end_time - begin_time);
136	
137	    return cheapest_paths;
138	}
