140	template<typename Heap>
141	void SerialConnectionRouter<Heap>::timing_driven_expand_cheapest(RRNodeId from_node,
142	                                                                 float new_total_cost,
143	                                                                 RRNodeId target_node,
144	                                                                 const t_conn_cost_params& cost_params,
145	                                                                 const t_bb& bounding_box,
146	                                                                 const t_bb& target_bb) {
147	    float best_total_cost = this->rr_node_route_inf_[from_node].path_cost;
148	    if (best_total_cost == new_total_cost) {
149	        // Explore from this node, since its total cost is exactly the same as
150	        // the best total cost ever seen for this node. Otherwise, prune this node
151	        // to reduce redundant work (i.e., unnecessary neighbor exploration).
152	        // `new_total_cost` is used here as an identifier to detect if the pair
153	        // (from_node or inode, new_total_cost) was the most recently pushed
154	        // element for the corresponding node.
155	        //
156	        // Note: For RCV, it often isn't searching for a shortest path; it is
157	        // searching for a path in the target delay range. So it might find a
158	        // path to node n that has a higher `backward_path_cost` but the `total_cost`
159	        // (including expected delay to sink, going through a cost function that
160	        // checks that against the target delay) might be lower than the previously
161	        // stored value. In that case we want to re-expand the node so long as
162	        // it doesn't create a loop. That `this->rcv_path_manager` should store enough
163	        // info for us to avoid loops.
164	        RTExploredNode current;
165	        current.index = from_node;
166	        current.backward_path_cost = this->rr_node_route_inf_[from_node].backward_path_cost;
167	        current.prev_edge = this->rr_node_route_inf_[from_node].prev_edge;
168	        current.R_upstream = this->rr_node_route_inf_[from_node].R_upstream;
169	
170	        VTR_LOGV_DEBUG(this->router_debug_, "    Better cost to %d\n", from_node);
171	        VTR_LOGV_DEBUG(this->router_debug_, "    New total cost: %g\n", new_total_cost);
172	        VTR_LOGV_DEBUG(this->router_debug_ && (current.prev_edge != RREdgeId::INVALID()),
173	                       "      Setting path costs for associated node %d (from %d edge %zu)\n",
174	                       from_node,
175	                       static_cast<size_t>(this->rr_graph_->edge_src_node(current.prev_edge)),
176	                       static_cast<size_t>(current.prev_edge));
177	
178	        timing_driven_expand_neighbours(current, cost_params, bounding_box, target_node, target_bb);
179	    } else {
180	        // Post-heap prune, do not re-explore from the current/new partial path as it
181	        // has worse cost than the best partial path to this node found so far
182	        VTR_LOGV_DEBUG(this->router_debug_, "    Worse cost to %d\n", from_node);
183	        VTR_LOGV_DEBUG(this->router_debug_, "    Old total cost: %g\n", best_total_cost);
184	        VTR_LOGV_DEBUG(this->router_debug_, "    New total cost: %g\n", new_total_cost);
185	    }
186	}
