188	template<typename Heap>
189	void SerialConnectionRouter<Heap>::timing_driven_expand_neighbours(const RTExploredNode& current,
190	                                                                   const t_conn_cost_params& cost_params,
191	                                                                   const t_bb& bounding_box,
192	                                                                   RRNodeId target_node,
193	                                                                   const t_bb& target_bb) {
194	    /* Puts all the rr_nodes adjacent to current on the heap. */
195	
196	    // For each node associated with the current heap element, expand all of it's neighbors
197	    auto edges = this->rr_nodes_.edge_range(current.index);
198	
199	    // This is a simple prefetch that prefetches:
200	    //  - RR node data reachable from this node
201	    //  - rr switch data to reach those nodes from this node.
202	    //
203	    // This code will be a NOP on compiler targets that do not have a
204	    // builtin to emit prefetch instructions.
205	    //
206	    // This code will be a NOP on CPU targets that lack prefetch instructions.
207	    // All modern x86 and ARM64 platforms provide prefetch instructions.
208	    //
209	    // This code delivers ~6-8% reduction in wallclock time when running Titan
210	    // benchmarks, and was specifically measured against the gsm_switch and
211	    // directrf vtr_reg_weekly running in high effort.
212	    //
213	    //  - directrf_stratixiv_arch_timing.blif
214	    //  - gsm_switch_stratixiv_arch_timing.blif
215	    //
216	    for (RREdgeId from_edge : edges) {
217	        RRNodeId to_node = this->rr_nodes_.edge_sink_node(from_edge);
218	        this->rr_nodes_.prefetch_node(to_node);
219	
220	        int switch_idx = this->rr_nodes_.edge_switch(from_edge);
221	        VTR_PREFETCH(&this->rr_switch_inf_[switch_idx], 0, 0);
222	    }
223	
224	    for (RREdgeId from_edge : edges) {
225	        RRNodeId to_node = this->rr_nodes_.edge_sink_node(from_edge);
226	        timing_driven_expand_neighbour(current,
227	                                       from_edge,
228	                                       to_node,
229	                                       cost_params,
230	                                       bounding_box,
231	                                       target_node,
232	                                       target_bb);
233	    }
234	}
235	
236	template<typename Heap>
237	void SerialConnectionRouter<Heap>::timing_driven_expand_neighbour(const RTExploredNode& current,
238	                                                                  RREdgeId from_edge,
239	                                                                  RRNodeId to_node,
240	                                                                  const t_conn_cost_params& cost_params,
241	                                                                  const t_bb& bounding_box,
242	                                                                  RRNodeId target_node,
243	                                                                  const t_bb& target_bb) {
244	    VTR_ASSERT(bounding_box.layer_max < (int)g_vpr_ctx.device().grid.get_num_layers());
245	
246	    const RRNodeId& from_node = current.index;
247	
248	    // BB-pruning
249	    // Disable BB-pruning if RCV is enabled, as this can make it harder for circuits with high negative hold slack to resolve this
250	    // TODO: Only disable pruning if the net has negative hold slack, maybe go off budgets
251	    if (!inside_bb(to_node, bounding_box)
252	        && !this->rcv_path_manager.is_enabled()) {
253	        VTR_LOGV_DEBUG(this->router_debug_,
254	                       "      Pruned expansion of node %d edge %zu -> %d"
255	                       " (to node location %d,%d,%d x %d,%d,%d outside of expanded"
256	                       " net bounding box %d,%d,%d x %d,%d,%d)\n",
257	                       from_node, size_t(from_edge), size_t(to_node),
258	                       this->rr_graph_->node_xlow(to_node), this->rr_graph_->node_ylow(to_node), this->rr_graph_->node_layer_low(to_node),
259	                       this->rr_graph_->node_xhigh(to_node), this->rr_graph_->node_yhigh(to_node), this->rr_graph_->node_layer_low(to_node),
260	                       bounding_box.xmin, bounding_box.ymin, bounding_box.layer_min,
261	                       bounding_box.xmax, bounding_box.ymax, bounding_box.layer_max);
262	        return; /* Node is outside (expanded) bounding box. */
263	    }
264	
265	    /* Prune away IPINs that lead to blocks other than the target one.  Avoids  *
266	     * the issue of how to cost them properly so they don't get expanded before *
267	     * more promising routes, but makes route-through (via CLBs) impossible.   *
268	     * Change this if you want to investigate route-throughs.                   */
269	    if (target_node != RRNodeId::INVALID()) {
270	        e_rr_type to_type = this->rr_graph_->node_type(to_node);
271	        if (to_type == e_rr_type::IPIN) {
272	            // Check if this IPIN leads to the target block
273	            // IPIN's of the target block should be contained within it's bounding box
274	            int to_xlow = this->rr_graph_->node_xlow(to_node);
275	            int to_ylow = this->rr_graph_->node_ylow(to_node);
276	            int to_layer = this->rr_graph_->node_layer_low(to_node);
277	            int to_xhigh = this->rr_graph_->node_xhigh(to_node);
278	            int to_yhigh = this->rr_graph_->node_yhigh(to_node);
279	            if (to_xlow < target_bb.xmin
280	                || to_ylow < target_bb.ymin
281	                || to_xhigh > target_bb.xmax
282	                || to_yhigh > target_bb.ymax
283	                || to_layer < target_bb.layer_min
284	                || to_layer > target_bb.layer_max) {
285	                VTR_LOGV_DEBUG(this->router_debug_,
286	                               "      Pruned expansion of node %d edge %zu -> %d"
287	                               " (to node is IPIN at %d,%d,%d x %d,%d,%d which does not"
288	                               " lead to target block %d,%d,%d x %d,%d,%d)\n",
289	                               from_node, size_t(from_edge), size_t(to_node),
290	                               to_xlow, to_ylow, to_layer,
291	                               to_xhigh, to_yhigh, to_layer,
292	                               target_bb.xmin, target_bb.ymin, target_bb.layer_min,
293	                               target_bb.xmax, target_bb.ymax, target_bb.layer_max);
294	                return;
295	            }
296	        }
297	    }
298	
299	    VTR_LOGV_DEBUG(this->router_debug_, "      Expanding node %d edge %zu -> %d\n",
300	                   from_node, size_t(from_edge), size_t(to_node));
301	
302	    // Check if the node exists in the route tree when RCV is enabled
303	    // Other pruning methods have been disabled when RCV is on, so this method is required to prevent "loops" from being created
304	    bool node_exists = false;
305	    if (this->rcv_path_manager.is_enabled()) {
306	        node_exists = this->rcv_path_manager.node_exists_in_tree(this->rcv_path_data[from_node],
307	                                                                 to_node);
308	    }
309	
310	    if (!node_exists || !this->rcv_path_manager.is_enabled()) {
311	        timing_driven_add_to_heap(cost_params,
312	                                  current,
313	                                  to_node,
314	                                  from_edge,
315	                                  target_node);
316	    }
317	}
