319	template<typename Heap>
320	void SerialConnectionRouter<Heap>::timing_driven_add_to_heap(const t_conn_cost_params& cost_params,
321	                                                             const RTExploredNode& current,
322	                                                             RRNodeId to_node,
323	                                                             const RREdgeId from_edge,
324	                                                             RRNodeId target_node) {
325	    const auto& device_ctx = g_vpr_ctx.device();
326	    const RRNodeId& from_node = current.index;
327	
328	    // Initialize the neighbor RTExploredNode
329	    RTExploredNode next;
330	    next.R_upstream = current.R_upstream;
331	    next.index = to_node;
332	    next.prev_edge = from_edge;
333	    next.total_cost = std::numeric_limits<float>::infinity(); // Not used directly
334	    next.backward_path_cost = current.backward_path_cost;
335	
336	    // Initialize RCV data struct if needed, otherwise it's set to nullptr
337	    this->rcv_path_manager.alloc_path_struct(next.path_data);
338	    // path_data variables are initialized to current values
339	    if (this->rcv_path_manager.is_enabled() && this->rcv_path_data[from_node]) {
340	        next.path_data->backward_cong = this->rcv_path_data[from_node]->backward_cong;
341	        next.path_data->backward_delay = this->rcv_path_data[from_node]->backward_delay;
342	    }
343	
344	    this->evaluate_timing_driven_node_costs(&next, cost_params, from_node, target_node);
345	
346	    float best_total_cost = this->rr_node_route_inf_[to_node].path_cost;
347	    float best_back_cost = this->rr_node_route_inf_[to_node].backward_path_cost;
348	
349	    float new_total_cost = next.total_cost;
350	    float new_back_cost = next.backward_path_cost;
351	
352	    // We need to only expand this node if it is a better path. And we need to
353	    // update its `rr_node_route_inf` data as we put it into the heap; there may
354	    // be other (previously explored) paths to this node in the heap already,
355	    // but they will be pruned when we pop those heap nodes later as we'll see
356	    // they have inferior costs to what is in the `rr_node_route_inf` data for
357	    // this node. More details can be found from the FPT'24 parallel connection
358	    // router paper.
359	    //
360	    // When RCV is enabled, prune based on the RCV-specific total path cost (see
361	    // in `compute_node_cost_using_rcv` in `evaluate_timing_driven_node_costs`)
362	    // to allow detours to get better QoR.
363	    if ((!this->rcv_path_manager.is_enabled() && best_back_cost > new_back_cost) || (this->rcv_path_manager.is_enabled() && best_total_cost > new_total_cost)) {
364	        VTR_LOGV_DEBUG(this->router_debug_, "      Expanding to node %d (%s)\n", to_node,
365	                       describe_rr_node(device_ctx.rr_graph,
366	                                        device_ctx.grid,
367	                                        device_ctx.rr_indexed_data,
368	                                        to_node,
369	                                        this->is_flat_)
370	                           .c_str());
371	        VTR_LOGV_DEBUG(this->router_debug_, "        New Total Cost %g New back Cost %g\n", new_total_cost, new_back_cost);
372	        //Add node to the heap only if the cost via the current partial path is less than the
373	        //best known cost, since there is no reason for the router to expand more expensive paths.
374	        //
375	        //Pre-heap prune to keep the heap small, by not putting paths which are known to be
376	        //sub-optimal (at this point in time) into the heap.
377	
378	        update_cheapest(next, from_node);
379	
380	        this->heap_.add_to_heap({new_total_cost, to_node});
381	        update_serial_router_stats(this->router_stats_,
382	                                   /*is_push=*/true,
383	                                   to_node,
384	                                   this->rr_graph_);
385	
386	    } else {
387	        VTR_LOGV_DEBUG(this->router_debug_, "      Didn't expand to %d (%s)\n", to_node, describe_rr_node(device_ctx.rr_graph, device_ctx.grid, device_ctx.rr_indexed_data, to_node, this->is_flat_).c_str());
388	        VTR_LOGV_DEBUG(this->router_debug_, "        Prev Total Cost %g Prev back Cost %g \n", best_total_cost, best_back_cost);
389	        VTR_LOGV_DEBUG(this->router_debug_, "        New Total Cost %g New back Cost %g \n", new_total_cost, new_back_cost);
390	    }
391	
392	    if (this->rcv_path_manager.is_enabled() && next.path_data != nullptr) {
393	        this->rcv_path_manager.free_path_struct(next.path_data);
394	    }
395	}
396	
397	template<typename Heap>
398	void SerialConnectionRouter<Heap>::add_route_tree_node_to_heap(
399	    const RouteTreeNode& rt_node,
400	    RRNodeId target_node,
401	    const t_conn_cost_params& cost_params,
402	    const t_bb& net_bb) {
403	    const auto& device_ctx = g_vpr_ctx.device();
404	    const RRNodeId inode = rt_node.inode;
405	    float backward_path_cost = cost_params.criticality * rt_node.Tdel;
406	    float R_upstream = rt_node.R_upstream;
407	
408	    /* Don't push to heap if not in bounding box: no-op for serial router, important for parallel router */
409	    if (!inside_bb(rt_node.inode, net_bb))
410	        return;
411	
412	    // After budgets are loaded, calculate delay cost as described by RCV paper
413	    /* R. Fung, V. Betz and W. Chow, "Slack Allocation and Routing to Improve FPGA Timing While
414	     * Repairing Short-Path Violations," in IEEE Transactions on Computer-Aided Design of
415	     * Integrated Circuits and Systems, vol. 27, no. 4, pp. 686-697, April 2008.*/
416	    // float expected_cost = router_lookahead_.get_expected_cost(inode, target_node, cost_params, R_upstream);
417	
418	    if (!this->rcv_path_manager.is_enabled()) {
419	        float expected_cost = this->router_lookahead_.get_expected_cost(inode, target_node, cost_params, R_upstream);
420	        float tot_cost = backward_path_cost + cost_params.astar_fac * std::max(0.f, expected_cost - cost_params.astar_offset);
421	        VTR_LOGV_DEBUG(this->router_debug_, "  Adding node %8d to heap from init route tree with cost %g (%s)\n",
422	                       inode,
423	                       tot_cost,
424	                       describe_rr_node(device_ctx.rr_graph, device_ctx.grid, device_ctx.rr_indexed_data, inode, this->is_flat_).c_str());
425	
426	        if (tot_cost > this->rr_node_route_inf_[inode].path_cost) {
427	            return;
428	        }
429	        add_to_mod_list(inode);
430	        this->rr_node_route_inf_[inode].path_cost = tot_cost;
431	        this->rr_node_route_inf_[inode].prev_edge = RREdgeId::INVALID();
432	        this->rr_node_route_inf_[inode].backward_path_cost = backward_path_cost;
433	        this->rr_node_route_inf_[inode].R_upstream = R_upstream;
434	        this->heap_.push_back({tot_cost, inode});
435	    } else {
436	        float expected_total_cost = this->compute_node_cost_using_rcv(cost_params, inode, target_node, rt_node.Tdel, 0, R_upstream);
437	
438	        add_to_mod_list(inode);
439	        this->rr_node_route_inf_[inode].path_cost = expected_total_cost;
440	        this->rr_node_route_inf_[inode].prev_edge = RREdgeId::INVALID();
441	        this->rr_node_route_inf_[inode].backward_path_cost = backward_path_cost;
442	        this->rr_node_route_inf_[inode].R_upstream = R_upstream;
443	
444	        this->rcv_path_manager.alloc_path_struct(this->rcv_path_data[inode]);
445	        this->rcv_path_data[inode]->backward_delay = rt_node.Tdel;
446	
447	        this->heap_.push_back({expected_total_cost, inode});
448	    }
449	
450	    update_serial_router_stats(this->router_stats_,
451	                               /*is_push=*/true,
452	                               inode,
453	                               this->rr_graph_);
454	
455	    if constexpr (VTR_ENABLE_DEBUG_LOGGING_CONST_EXPR) {
456	        this->router_stats_->rt_node_pushes[this->rr_graph_->node_type(inode)]++;
457	    }
458	}
