460	std::unique_ptr<ConnectionRouterInterface> make_serial_connection_router(e_heap_type heap_type,
461	                                                                         const DeviceGrid& grid,
462	                                                                         const RouterLookahead& router_lookahead,
463	                                                                         const t_rr_graph_storage& rr_nodes,
464	                                                                         const RRGraphView* rr_graph,
465	                                                                         const std::vector<t_rr_rc_data>& rr_rc_data,
466	                                                                         const vtr::vector<RRSwitchId, t_rr_switch_inf>& rr_switch_inf,
467	                                                                         vtr::vector<RRNodeId, t_rr_node_route_inf>& rr_node_route_inf,
468	                                                                         bool is_flat,
469	                                                                         int route_verbosity) {
470	    switch (heap_type) {
471	        case e_heap_type::BINARY_HEAP:
472	            return std::make_unique<SerialConnectionRouter<BinaryHeap>>(
473	                grid,
474	                router_lookahead,
475	                rr_nodes,
476	                rr_graph,
477	                rr_rc_data,
478	                rr_switch_inf,
479	                rr_node_route_inf,
480	                is_flat,
481	                route_verbosity);
482	        case e_heap_type::FOUR_ARY_HEAP:
483	            return std::make_unique<SerialConnectionRouter<FourAryHeap>>(
484	                grid,
485	                router_lookahead,
486	                rr_nodes,
487	                rr_graph,
488	                rr_rc_data,
489	                rr_switch_inf,
490	                rr_node_route_inf,
491	                is_flat,
492	                route_verbosity);
493	        default:
494	            VPR_FATAL_ERROR(VPR_ERROR_ROUTE, "Unknown heap_type %d",
495	                            heap_type);
496	    }
497	}
