499	/** This function is only used for the serial connection router since some
500	 * statistic variables in router_stats are not thread-safe for the parallel
501	 * connection router. To update router_stats (more precisely heap_pushes/pops)
502	 * for parallel connection router, we use the MultiQueue internal statistics
503	 * method instead. */
504	inline void update_serial_router_stats(RouterStats* router_stats,
505	                                       bool is_push,
506	                                       RRNodeId rr_node_id,
507	                                       const RRGraphView* rr_graph) {
508	    if (is_push) {
509	        router_stats->heap_pushes++;
510	    } else {
511	        router_stats->heap_pops++;
512	    }
513	
514	    if constexpr (VTR_ENABLE_DEBUG_LOGGING_CONST_EXPR) {
515	        auto node_type = rr_graph->node_type(rr_node_id);
516	        VTR_ASSERT(node_type != e_rr_type::NUM_RR_TYPES);
517	
518	        if (is_inter_cluster_node(*rr_graph, rr_node_id)) {
519	            if (is_push) {
520	                router_stats->inter_cluster_node_pushes++;
521	                router_stats->inter_cluster_node_type_cnt_pushes[node_type]++;
522	            } else {
523	                router_stats->inter_cluster_node_pops++;
524	                router_stats->inter_cluster_node_type_cnt_pops[node_type]++;
525	            }
526	        } else {
527	            if (is_push) {
528	                router_stats->intra_cluster_node_pushes++;
529	                router_stats->intra_cluster_node_type_cnt_pushes[node_type]++;
530	            } else {
531	                router_stats->intra_cluster_node_pops++;
532	                router_stats->intra_cluster_node_type_cnt_pops[node_type]++;
533	            }
534	        }
535	    }
536	}
