std::unique_ptr<HeapInterface> make_heap(e_heap_type heap_type) {
    switch (heap_type) {
        case e_heap_type::BINARY_HEAP:
            return std::make_unique<BinaryHeap>();
        case e_heap_type::FOUR_ARY_HEAP:
            return std::make_unique<FourAryHeap>();
